module top_module(
    input DATA, LATCH,
    output Q, QNOT
    );wire d, l;
    reg q, qnot;

    wire inverted_latch_output = DATA;
    assign d = inverted_latch_output;
    assign l = LATCH;

    always@(d or l)
        if(l)begin
            q <= d;
            qnot <= ~d;
        end

    assign Q = q;
    assign QNOT = qnot;endmodule
